import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Home, Search, BookOpen, Phone, User } from 'lucide-react';

export const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsOpen(false);
  }, [location]);

  const navLinks = [
    { name: 'Home', path: '/', icon: <Home size={18} /> },
    { name: 'Listings', path: '/listings', icon: <Search size={18} /> },
    { name: 'Journal', path: '/blog', icon: <BookOpen size={18} /> },
    { name: 'About', path: '/about', icon: <User size={18} /> },
    { name: 'Contact', path: '/contact', icon: <Phone size={18} /> },
  ];

  return (
    <nav 
      className={`fixed w-full z-50 transition-all duration-300 ${
        scrolled ? 'bg-forge-navy shadow-lg py-3' : 'bg-forge-navy/90 py-5'
      } text-white`}
    >
      <div className="container mx-auto px-6 flex justify-between items-center">
        {/* Logo */}
        <Link to="/" className="flex flex-col">
          <span className="text-xl font-bold tracking-widest">THE FORGE</span>
          <span className="text-[8px] uppercase tracking-[0.3em] text-forge-gold">Properties</span>
        </Link>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center space-x-8">
          {navLinks.map((link) => (
            <Link
              key={link.name}
              to={link.path}
              className={`text-xs uppercase tracking-widest font-bold hover:text-forge-gold transition-colors ${
                location.pathname === link.path ? 'text-forge-gold' : ''
              }`}
            >
              {link.name}
            </Link>
          ))}
          <Link 
            to="/listings"
            className="bg-forge-gold text-forge-navy px-5 py-2.5 rounded font-bold uppercase tracking-widest text-[10px] hover:bg-white transition-colors"
          >
            Find a Home
          </Link>
        </div>

        {/* Mobile Menu Toggle */}
        <button 
          className="md:hidden p-2 hover:bg-white/10 rounded"
          onClick={() => setIsOpen(!isOpen)}
        >
          {isOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Mobile Menu Content */}
      <div 
        className={`md:hidden absolute top-full left-0 w-full bg-forge-navy border-t border-white/10 transition-all duration-300 overflow-hidden ${
          isOpen ? 'max-h-screen opacity-100' : 'max-h-0 opacity-0'
        }`}
      >
        <div className="p-6 space-y-4">
          {navLinks.map((link) => (
            <Link
              key={link.name}
              to={link.path}
              className="flex items-center gap-4 text-sm font-bold uppercase tracking-widest py-2 border-b border-white/5 last:border-0"
            >
              <span className="text-forge-gold">{link.icon}</span>
              {link.name}
            </Link>
          ))}
          <Link 
            to="/listings"
            className="block bg-forge-gold text-forge-navy text-center py-4 rounded font-bold uppercase tracking-widest text-xs"
          >
            Find a Home
          </Link>
        </div>
      </div>
    </nav>
  );
};

